<!DOCTYPE html>
<html lang="ja">

	<head>
		<meta charset="UTF-8" />
		<meta name="viewport" content="width=device-width, initial-scale=1.0" />
		<title>猫の間違い探しゲーム</title>
		<style>
			:root {
				--bg: #6e4720;
				--panel: #fff8ef;
				--accent: #f2e6bf;
				--text: #3a2412;
				--good: #2e7d32;
				--bad: #a33a3a;
				--mark: #ff5252;
				--hint: #ffcc4d;
			}

			* {
				box-sizing: border-box;
			}

			body {
				margin: 0;
				font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
				background: linear-gradient(180deg, #7a5127 0%, var(--bg) 100%);
				color: var(--text);
			}

			.page {
				max-width: 1200px;
				margin: 0 auto;
				padding: 20px 16px 40px;
			}

			.header {
				background: rgba(255, 248, 239, 0.95);
				border-radius: 24px;
				padding: 18px 20px;
				box-shadow: 0 10px 30px rgba(0, 0, 0, 0.12);
				display: grid;
				gap: 12px;
			}

			h1 {
				margin: 0;
				font-size: clamp(1.6rem, 4vw, 2.6rem);
			}

			.sub {
				margin: 0;
				line-height: 1.6;
				color: #5b3b20;
				font-size: 0.98rem;
			}

			.toolbar {
				display: flex;
				flex-wrap: wrap;
				gap: 10px;
				align-items: center;
				justify-content: space-between;
				margin-top: 8px;
			}

			.stats {
				display: flex;
				flex-wrap: wrap;
				gap: 10px;
				align-items: center;
			}

			.pill {
				background: #fff;
				border-radius: 999px;
				padding: 10px 14px;
				font-weight: 700;
				box-shadow: inset 0 0 0 1px rgba(58, 36, 18, 0.08);
			}

			.actions {
				display: flex;
				flex-wrap: wrap;
				gap: 10px;
			}

			button {
				appearance: none;
				border: 0;
				border-radius: 16px;
				padding: 11px 16px;
				font-size: 0.96rem;
				font-weight: 700;
				cursor: pointer;
				background: #fff;
				color: var(--text);
				box-shadow: 0 6px 20px rgba(0, 0, 0, 0.10);
				transition: transform .15s ease, box-shadow .15s ease, opacity .15s ease;
			}

			button:hover {
				transform: translateY(-1px);
				box-shadow: 0 8px 22px rgba(0, 0, 0, 0.14);
			}

			button.primary {
				background: var(--accent);
			}

			.board-wrap {
				margin-top: 18px;
				background: rgba(255, 248, 239, 0.95);
				border-radius: 28px;
				padding: 16px;
				box-shadow: 0 12px 36px rgba(0, 0, 0, 0.12);
			}

			.board {
				position: relative;
				width: 100%;
				overflow: hidden;
				border-radius: 20px;
				user-select: none;
				-webkit-user-select: none;
				background: #fff;
			}

			.board img {
				display: block;
				width: 100%;
				height: auto;
			}

			.marker {
				position: absolute;
				width: 44px;
				height: 44px;
				margin-left: -22px;
				margin-top: -22px;
				border: 4px solid var(--mark);
				border-radius: 50%;
				pointer-events: none;
				box-shadow: 0 0 0 4px rgba(255, 255, 255, 0.9), 0 4px 16px rgba(0, 0, 0, 0.2);
				animation: pop .2s ease;
			}

			.marker.answer {
				border-color: var(--hint);
				opacity: 0.9;
			}

			.marker.hint {
				border-color: var(--hint);
				animation: pulse 1s infinite;
			}

			.toast {
				min-height: 28px;
				margin-top: 14px;
				font-weight: 700;
				padding-left: 6px;
			}

			.toast.good {
				color: var(--good);
			}

			.toast.bad {
				color: var(--bad);
			}

			.footer-note {
				margin-top: 10px;
				font-size: 0.92rem;
				color: #6b4a2b;
			}

			.complete {
				margin-top: 14px;
				padding: 16px;
				background: #fff4cc;
				border-radius: 20px;
				display: none;
				font-weight: 700;
				line-height: 1.7;
			}

			.complete.show {
				display: block;
			}

			@keyframes pop {
				from {
					transform: scale(0.6);
					opacity: 0.2;
				}

				to {
					transform: scale(1);
					opacity: 1;
				}
			}

			@keyframes pulse {
				0% {
					transform: scale(0.95);
					opacity: 0.7;
				}

				50% {
					transform: scale(1.08);
					opacity: 1;
				}

				100% {
					transform: scale(0.95);
					opacity: 0.7;
				}
			}

			@media (max-width: 640px) {
				.page {
					padding: 12px 10px 28px;
				}

				.header,
				.board-wrap {
					border-radius: 20px;
				}

				.board-wrap {
					padding: 10px;
				}

				.marker {
					width: 34px;
					height: 34px;
					margin-left: -17px;
					margin-top: -17px;
				}
			}

		</style>
	</head>

	<body>
		<div class="page">
			<section class="header">
				<div>
					<h1>猫の間違い探しゲーム</h1>
					<p class="sub">左右のイラストを見比べて、間違いをタップしてみてください。<strong>10個</strong>見つけるとクリアです。ヒントや答え表示も入れてあります。</p>
				</div>
				<div class="toolbar">
					<div class="stats">
						<div class="pill">見つけた数: <span id="foundCount">0</span> / 10</div>
						<div class="pill">タイム: <span id="timer">00:00</span></div>
					</div>
					<div class="actions">
						<button class="primary" id="hintBtn">ヒント</button>
						<button id="answerBtn">答えを表示</button>
						<button id="resetBtn">リセット</button>
					</div>
				</div>
			</section>
			<section class="board-wrap">
				<div class="board" id="board">
					<img id="gameImage" src="data:image/png;base64," alt="猫の間違い探し画像" draggable="false" />
				</div>
				<div class="toast" id="toast">画像をタップしてスタート</div>
				<div class="complete" id="completeBox"></div>
				<div class="footer-note">見つけにくいところもあるので、少し広めに判定しています。</div>
			</section>
		</div>
		<script>
			const ORIGINAL_WIDTH = 2000;
			const ORIGINAL_HEIGHT = 1000;
			const targets = [{
				"id": "tinycat",
				"name": "小さな猫アイコン",
				"points": [{
					"x": 474,
					"y": 86
				}],
				"radius": 32
			}, {
				"id": "bowl",
				"name": "ごはん皿",
				"points": [{
					"x": 662,
					"y": 138
				}, {
					"x": 1445,
					"y": 131
				}],
				"radius": 46
			}, {
				"id": "heart",
				"name": "ハートの写真",
				"points": [{
					"x": 798,
					"y": 96
				}, {
					"x": 1660,
					"y": 108
				}],
				"radius": 72
			}, {
				"id": "camera",
				"name": "カメラ",
				"points": [{
					"x": 251,
					"y": 356
				}, {
					"x": 1120,
					"y": 355
				}],
				"radius": 48
			}, {
				"id": "exclaim",
				"name": "びっくりマーク",
				"points": [{
					"x": 553,
					"y": 281
				}, {
					"x": 1383,
					"y": 280
				}],
				"radius": 52
			}, {
				"id": "question",
				"name": "はてなマーク",
				"points": [{
					"x": 810,
					"y": 241
				}, {
					"x": 1648,
					"y": 243
				}],
				"radius": 52
			}, {
				"id": "bigcircle",
				"name": "大きな丸",
				"points": [{
					"x": 808,
					"y": 390
				}, {
					"x": 1600,
					"y": 388
				}],
				"radius": 125
			}, {
				"id": "text",
				"name": "文字",
				"points": [{
					"x": 286,
					"y": 548
				}, {
					"x": 1250,
					"y": 548
				}],
				"radius": 82
			}, {
				"id": "paw1",
				"name": "足あと①",
				"points": [{
					"x": 650,
					"y": 475
				}, {
					"x": 1485,
					"y": 475
				}],
				"radius": 62
			}, {
				"id": "paw2",
				"name": "足あと②",
				"points": [{
					"x": 650,
					"y": 640
				}, {
					"x": 1485,
					"y": 640
				}],
				"radius": 62
			}];
			const board = document.getElementById('board');
			const img = document.getElementById('gameImage');
			const foundCountEl = document.getElementById('foundCount');
			const timerEl = document.getElementById('timer');
			const toast = document.getElementById('toast');
			const completeBox = document.getElementById('completeBox');
			const hintBtn = document.getElementById('hintBtn');
			const answerBtn = document.getElementById('answerBtn');
			const resetBtn = document.getElementById('resetBtn');
			let found = new Set();
			let showingAnswers = false;
			let activeHint = null;
			let startedAt = null;
			let timerId = null;

			function formatTime(ms) {
				const total = Math.floor(ms / 1000);
				const m = String(Math.floor(total / 60)).padStart(2, '0');
				const s = String(total % 60).padStart(2, '0');
				return `${m}:${s}`;
			}

			function ensureTimerStarted() {
				if (startedAt) return;
				startedAt = Date.now();
				timerId = setInterval(() => {
					timerEl.textContent = formatTime(Date.now() - startedAt);
				}, 250);
			}

			function stopTimer() {
				if (timerId) clearInterval(timerId);
				timerId = null;
			}

			function setToast(message, type = '') {
				toast.textContent = message;
				toast.className = 'toast' + (type ? ` ${type}` : '');
			}

			function clearDynamicMarkers() {
				board.querySelectorAll('.marker').forEach(el => el.remove());
			}

			function addMarker(x, y, className = '') {
				const marker = document.createElement('div');
				marker.className = `marker ${className}`.trim();
				marker.style.left = `${(x / ORIGINAL_WIDTH) * 100}%`;
				marker.style.top = `${(y / ORIGINAL_HEIGHT) * 100}%`;
				board.appendChild(marker);
			}

			function renderMarkers() {
				clearDynamicMarkers();
				targets.forEach(target => {
					if (found.has(target.id) || showingAnswers) {
						target.points.forEach(point => addMarker(point.x, point.y, showingAnswers && !found.has(target.id) ? 'answer' : ''));
					}
				});
				if (activeHint && !found.has(activeHint.id) && !showingAnswers) {
					const p = activeHint.points[0];
					addMarker(p.x, p.y, 'hint');
				}
			}

			function updateUI() {
				foundCountEl.textContent = found.size;
				renderMarkers();
				if (found.size === targets.length) {
					stopTimer();
					const elapsed = startedAt ? formatTime(Date.now() - startedAt) : '00:00';
					completeBox.innerHTML = `🎉 クリア！ 10個ぜんぶ見つけました。<br>クリアタイム: <strong>${elapsed}</strong>`;
					completeBox.classList.add('show');
					setToast('全部見つけました！おめでとうございます。', 'good');
				} else {
					completeBox.classList.remove('show');
				}
			}

			function distance(a, b) {
				const dx = a.x - b.x;
				const dy = a.y - b.y;
				return Math.sqrt(dx * dx + dy * dy);
			}

			function detectTarget(x, y) {
				for (const target of targets) {
					for (const point of target.points) {
						if (distance({
								x,
								y
							}, point) <= target.radius) {
							return target;
						}
					}
				}
				return null;
			}
			board.addEventListener('click', (event) => {
				const rect = board.getBoundingClientRect();
				const x = ((event.clientX - rect.left) / rect.width) * ORIGINAL_WIDTH;
				const y = ((event.clientY - rect.top) / rect.height) * ORIGINAL_HEIGHT;
				ensureTimerStarted();
				activeHint = null;
				const target = detectTarget(x, y);
				if (!target) {
					setToast('そこは違うみたい。もう一度さがしてみてください。', 'bad');
					renderMarkers();
					return;
				}
				if (found.has(target.id)) {
					setToast('そこはもう見つけています。', 'good');
					renderMarkers();
					return;
				}
				found.add(target.id);
				setToast(`正解！ 「${target.name}」を見つけました。`, 'good');
				updateUI();
			});
			hintBtn.addEventListener('click', () => {
				const next = targets.find(t => !found.has(t.id));
				if (!next) {
					setToast('もう全部見つけています。', 'good');
					return;
				}
				ensureTimerStarted();
				activeHint = next;
				setToast('ヒントを出しました。黄色の丸の近くを見てみてください。');
				renderMarkers();
			});
			answerBtn.addEventListener('click', () => {
				showingAnswers = !showingAnswers;
				answerBtn.textContent = showingAnswers ? '答えを隠す' : '答えを表示';
				activeHint = null;
				setToast(showingAnswers ? '答えを表示しています。' : '答えを隠しました。');
				renderMarkers();
			});
			resetBtn.addEventListener('click', () => {
				found = new Set();
				showingAnswers = false;
				activeHint = null;
				startedAt = null;
				stopTimer();
				timerEl.textContent = '00:00';
				answerBtn.textContent = '答えを表示';
				completeBox.classList.remove('show');
				setToast('リセットしました。画像をタップしてスタート');
				updateUI();
			});
			updateUI();

		</script>
	</body>

</html>
